function ClinicalGuidelinesView() {
  const [search, setSearch] = useState('');
  const [activeId, setActiveId] = useState(null);
  const active = CLINICAL_GUIDELINES.find(g => g.id === activeId);
  const filtered = CLINICAL_GUIDELINES.filter(g => !search || (g.title + g.cat + g.summary).toLowerCase().includes(search.toLowerCase()));

  return (
    <div className="flex-1 min-h-0 flex flex-col">
      <div className="px-4 py-3 shrink-0" style={{ borderBottom: '1px solid var(--border)' }}>
        <h2 className="font-black text-xl flex items-center gap-2">📋 Clinical Guidelines</h2>
        <p className="text-xs opacity-40 mt-0.5">Evidence-based management protocols</p>
        {!active && (
          <input value={search} onChange={e => setSearch(e.target.value)} placeholder="Search guidelines…"
            className="w-full glass-input rounded-xl px-4 py-2.5 text-sm outline-none mt-3"
            style={{ background: 'var(--surface,var(--card))', border: '1px solid var(--border)' }} />
        )}
      </div>
      <div className="flex-1 min-h-0 overflow-y-auto custom-scrollbar p-4 space-y-3">
        {active ? (
          <div className="space-y-4 animate-fade-in-up">
            <div className="flex items-center gap-3">
              <button onClick={() => setActiveId(null)} className="glass w-9 h-9 rounded-xl flex items-center justify-center"><ChevronLeft size={16} /></button>
              <div>
                <h2 className="font-bold">{active.title}</h2>
                <p className="text-xs opacity-40">{active.cat} · Updated {active.year}</p>
              </div>
            </div>
            <div className="glass rounded-2xl p-4" style={{ border: '1px solid var(--accent)/20', background: 'var(--accent)/05' }}>
              <p className="text-sm font-bold leading-relaxed">{active.summary}</p>
            </div>

            {/* Stepwise algorithm */}
            <div className="space-y-0">
              {active.steps.map((s, i) => (
                <div key={i} className="flex gap-4">
                  <div className="flex flex-col items-center shrink-0">
                    <div className="w-8 h-8 rounded-xl flex items-center justify-center text-xs font-bold"
                      style={{ background: 'var(--accent)', color: '#fff' }}>{i + 1}</div>
                    {i < active.steps.length - 1 && <div className="w-0.5 flex-1 my-1" style={{ background: 'var(--accent)/30' }} />}
                  </div>
                  <div className="flex-1 pb-4">
                    <h3 className="font-bold text-sm">{s.step}</h3>
                    <p className="text-xs opacity-60 leading-relaxed mt-1">{s.detail}</p>
                  </div>
                </div>
              ))}
            </div>

            {/* Key points */}
            <div className="glass rounded-2xl p-5" style={{ border: '1px solid #f59e0b20', background: '#f59e0b05' }}>
              <h3 className="font-bold text-sm flex items-center gap-2 mb-3" style={{ color: '#f59e0b' }}>💡 Key Points</h3>
              <div className="space-y-2">
                {active.keyPoints.map((kp, i) => (
                  <div key={i} className="flex gap-2 text-xs">
                    <span style={{ color: '#f59e0b' }}>▸</span>
                    <span className="opacity-70 leading-relaxed">{kp}</span>
                  </div>
                ))}
              </div>
            </div>
          </div>
        ) : (
          filtered.map(g => (
            <button key={g.id} onClick={() => setActiveId(g.id)}
              className="w-full glass rounded-2xl p-5 text-left transition-all card-hover"
              style={{ border: '1px solid var(--border)' }}>
              <div className="flex items-start justify-between gap-3 mb-2">
                <h3 className="font-bold">{g.title}</h3>
                <span className="px-2 py-0.5 rounded-lg text-xs font-bold shrink-0" style={{ background: 'var(--accent)/10', color: 'var(--accent)' }}>{g.cat}</span>
              </div>
              <p className="text-xs opacity-60 leading-relaxed line-clamp-2">{g.summary}</p>
              <div className="flex items-center gap-2 mt-2">
                <span className="text-xs opacity-30">{g.steps.length} steps</span>
                <span className="text-xs opacity-30">·</span>
                <span className="text-xs opacity-30">{g.year}</span>
              </div>
            </button>
          ))
        )}
        {!active && filtered.length === 0 && <div className="empty-state py-12"><p className="font-bold mt-4">No guidelines found</p></div>}
      </div>
    </div>
  );
}

/* ═══════════════════════════════════════════════════════════════════
   PATIENT HANDOUT GENERATOR — AI creates patient education
═══════════════════════════════════════════════════════════════════ */
function PatientHandoutView({ settings, addToast }) {
  const [condition, setCondition] = useState('');
  const [language, setLanguage] = useState('English');
  const [readingLevel, setReadingLevel] = useState('6th grade');
  const [loading, setLoading] = useState(false);
  const [handout, setHandout] = useState('');
  const [saved, setSaved] = useState(() => { try { return JSON.parse(localStorage.getItem('mariam_handouts') || '[]'); } catch { return []; } });

  const generate = async () => {
    if (!condition.trim()) { addToast('Enter a condition', 'warn'); return; }
    if (!settings.apiKey) { addToast('Set an API key in Settings', 'warn'); return; }
    setLoading(true); setHandout('');
    try {
      await callAIStreaming(
        `Create a patient education handout in ${language} at a ${readingLevel} reading level for: "${condition}".

Include these sections with headers (use ## for headers):
## What is ${condition}?
## Causes
## Symptoms to Watch For
## Treatment Options
## When to Seek Emergency Care
## Lifestyle Tips
## Questions to Ask Your Doctor

Keep language simple, compassionate, and clear. Use bullet points. About 400-500 words.`,
        chunk => { setHandout(p => p + chunk); },
        settings, 800
      );
    } catch (e) { addToast('Generation failed', 'error'); }
    setLoading(false);
  };

  const saveHandout = () => {
    if (!handout) return;
    const entry = { condition, language, handout, ts: Date.now() };
    const updated = [entry, ...saved.slice(0, 19)];
    setSaved(updated);
    localStorage.setItem('mariam_handouts', JSON.stringify(updated));
    addToast('Handout saved ✓', 'success');
  };

  const copyHandout = () => {
    navigator.clipboard?.writeText(handout);
    addToast('Copied ✓', 'success');
  };

  return (
    <div className="flex-1 min-h-0 flex flex-col">
      <div className="px-4 py-3 shrink-0" style={{ borderBottom: '1px solid var(--border)' }}>
        <h2 className="font-black text-xl flex items-center gap-2">📄 Patient Handouts</h2>
        <p className="text-xs opacity-40 mt-0.5">AI-generated patient education materials</p>
      </div>
      <div className="flex-1 min-h-0 overflow-y-auto custom-scrollbar p-4 space-y-4">
        <div className="glass rounded-2xl p-5 space-y-4" style={{ border: '1px solid var(--border)' }}>
          <div>
            <label className="text-xs font-bold opacity-40 uppercase tracking-widest block mb-2">Condition / Topic</label>
            <input value={condition} onChange={e => setCondition(e.target.value)} placeholder="e.g. Type 2 Diabetes, Hypertension, Asthma…"
              className="w-full glass-input rounded-xl px-4 py-2.5 text-sm outline-none"
              style={{ background: 'var(--surface,var(--card))', border: '1px solid var(--border)' }} />
          </div>
          <div className="grid grid-cols-2 gap-3">
            <div>
              <label className="text-xs font-bold opacity-40 uppercase tracking-widest block mb-2">Language</label>
              <select value={language} onChange={e => setLanguage(e.target.value)}
                className="w-full glass-input rounded-xl px-4 py-2.5 text-sm outline-none"
                style={{ background: 'var(--surface,var(--card))', border: '1px solid var(--border)' }}>
                {['English', 'Arabic', 'Spanish', 'French', 'German', 'Chinese', 'Hindi', 'Portuguese', 'Korean', 'Japanese', 'Turkish', 'Russian'].map(l => <option key={l}>{l}</option>)}
              </select>
            </div>
            <div>
              <label className="text-xs font-bold opacity-40 uppercase tracking-widest block mb-2">Reading Level</label>
              <select value={readingLevel} onChange={e => setReadingLevel(e.target.value)}
                className="w-full glass-input rounded-xl px-4 py-2.5 text-sm outline-none"
                style={{ background: 'var(--surface,var(--card))', border: '1px solid var(--border)' }}>
                {['4th grade', '6th grade', '8th grade', 'High school', 'College'].map(l => <option key={l}>{l}</option>)}
              </select>
            </div>
          </div>
          <div className="flex gap-2 flex-wrap">
            {['Type 2 Diabetes', 'Hypertension', 'Asthma', 'GERD', 'Heart Failure', 'COPD', 'Migraine', 'Osteoarthritis'].map(c => (
              <button key={c} onClick={() => setCondition(c)}
                className="glass px-2.5 py-1 rounded-lg text-xs transition-all hover:opacity-80"
                style={{ border: '1px solid var(--border)', opacity: condition === c ? 1 : .5 }}>
                {c}
              </button>
            ))}
          </div>
          <button onClick={generate} disabled={loading || !condition.trim()}
            className="btn-accent w-full py-3 rounded-xl font-bold flex items-center justify-center gap-2">
            {loading ? <><Loader2 size={16} className="animate-spin" /> Generating…</> : <><Sparkles size={16} /> Generate Handout</>}
          </button>
        </div>

        {handout && (
          <div className="glass rounded-2xl p-5 animate-fade-in-up" style={{ border: '1px solid var(--border)' }}>
            <div className="flex items-center justify-between mb-4">
              <h3 className="font-bold text-sm">📄 {condition}</h3>
              <div className="flex gap-2">
                <button onClick={copyHandout} className="glass px-3 py-1.5 rounded-xl text-xs font-bold flex items-center gap-1"
                  style={{ border: '1px solid var(--border)' }}><Copy size={11} /> Copy</button>
                <button onClick={saveHandout} className="glass px-3 py-1.5 rounded-xl text-xs font-bold flex items-center gap-1"
                  style={{ color: 'var(--accent)', border: '1px solid var(--accent)/30' }}><Save size={11} /> Save</button>
              </div>
            </div>
            <div className="prose prose-sm max-w-none text-sm opacity-80 leading-relaxed whitespace-pre-wrap">{handout}</div>
          </div>
        )}

        {saved.length > 0 && !handout && (
          <div className="glass rounded-2xl p-4" style={{ border: '1px solid var(--border)' }}>
            <h3 className="text-xs font-bold uppercase tracking-widest opacity-40 mb-3">Saved Handouts</h3>
            {saved.slice(0, 5).map((h, i) => (
              <button key={i} onClick={() => { setCondition(h.condition); setHandout(h.handout); }}
                className="w-full flex items-center justify-between py-2 text-left hover:opacity-80 transition-all">
                <div>
                  <span className="text-sm font-bold">{h.condition}</span>
                  <span className="text-xs opacity-30 ml-2">({h.language})</span>
                </div>
                <span className="text-xs opacity-30">{new Date(h.ts).toLocaleDateString()}</span>
              </button>
            ))}
          </div>
        )}
      </div>
    </div>
  );
}

/* ═══════════════════════════════════════════════════════════════════
   PROCEDURE CHECKLIST VIEW — step-by-step clinical procedures
═══════════════════════════════════════════════════════════════════ */
const PROCEDURE_CHECKLISTS = [
  { id: 'central_line', title: 'Central Venous Catheter (IJ)', cat: 'Critical Care', difficulty: 'Advanced', time: '30-45 min',
    equipment: ['CVC kit (triple lumen)', 'Ultrasound + sterile probe cover', 'Sterile gown, gloves, drapes', 'Chlorhexidine prep', 'Lidocaine 1%', 'Sterile saline flush × 3', 'Suture material (silk 2-0)', 'Sterile dressing (tegaderm)'],
    steps: [
      { text: 'Obtain informed consent', critical: false },
      { text: 'Position: Trendelenburg, head turned contralateral', critical: false },
      { text: 'Full sterile barrier precautions (cap, mask, gown, gloves, full drape)', critical: true },
      { text: 'Identify IJ vein with ultrasound (lateral to carotid artery)', critical: true },
      { text: 'Prep skin with chlorhexidine (2 min scrub, dry 30 sec)', critical: true },
      { text: 'Anesthetize skin with lidocaine', critical: false },
      { text: 'Insert needle under real-time US guidance at 45° angle', critical: true },
      { text: 'Aspirate dark venous blood (confirm venous, not arterial)', critical: true },
      { text: 'Thread guidewire through needle (should pass easily)', critical: true },
      { text: 'Confirm wire on US in vein (long-axis view)', critical: true },
      { text: 'Nick skin with scalpel, dilate tract', critical: false },
      { text: 'Thread catheter over wire to appropriate depth (12-15 cm right IJ)', critical: false },
      { text: 'REMOVE GUIDEWIRE', critical: true },
      { text: 'Aspirate and flush all ports', critical: true },
      { text: 'Secure with suture and apply sterile dressing', critical: false },
      { text: 'Confirm placement with CXR (tip at cavo-atrial junction)', critical: true },
    ],
    pearls: ['ALWAYS confirm wire removed before leaving bedside', 'CXR mandatory to rule out pneumothorax', 'Never force the wire — if resistance, reposition', 'Right IJ preferred (straight path to SVC)'] },
  { id: 'lumbar_puncture', title: 'Lumbar Puncture', cat: 'Neurology', difficulty: 'Intermediate', time: '20-30 min',
    equipment: ['LP kit (spinal needle 20-22G, manometer)', 'Sterile drapes, gown, gloves', 'Chlorhexidine prep', 'Lidocaine 1%', 'Collection tubes × 4', 'Sterile dressing'],
    steps: [
      { text: 'Check: CT head if indicated (papilledema, focal neuro signs, immunocompromised)', critical: true },
      { text: 'Check platelet count and coagulation (INR <1.5, Plt >50k)', critical: true },
      { text: 'Position: lateral decubitus (fetal position) or sitting', critical: false },
      { text: 'Identify L3-L4 or L4-L5 interspace (iliac crest line = L4)', critical: false },
      { text: 'Full sterile prep and drape', critical: true },
      { text: 'Anesthetize skin and deeper tissues with lidocaine', critical: false },
      { text: 'Insert spinal needle bevel up (midline, angled slightly cephalad)', critical: false },
      { text: 'Advance through ligamentum flavum — feel "pop" into subarachnoid space', critical: false },
      { text: 'Remove stylet, observe CSF flow', critical: false },
      { text: 'Measure opening pressure with manometer (normal 6-20 cmH₂O)', critical: true },
      { text: 'Collect 1-2 mL in each of 4 tubes (cell count, glucose/protein, micro, cytology/special)', critical: false },
      { text: 'Replace stylet, remove needle, apply dressing', critical: false },
      { text: 'Patient supine × 1 hour (reduces post-LP headache)', critical: false },
    ],
    pearls: ['Tube 1: cell count + protein. Tube 4: cell count (compare for traumatic tap vs SAH)', 'Post-LP headache: positional, improved lying flat. Blood patch if persistent', 'Send CSF glucose WITH serum glucose (ratio is key)', 'Xanthochromia (yellow CSF) = subarachnoid hemorrhage >6h old'] },
  { id: 'intubation', title: 'Endotracheal Intubation (RSI)', cat: 'Emergency', difficulty: 'Advanced', time: '10-15 min',
    equipment: ['Laryngoscope (Mac 3-4 or video laryngoscope)', 'ETT (7.0-7.5 women, 8.0-8.5 men)', 'BVM + O₂ source', 'Suction (Yankauer)', 'Stylet', 'Induction agent: Ketamine 1-2mg/kg or Propofol 1-2mg/kg', 'Paralytic: Succinylcholine 1.5mg/kg or Rocuronium 1.2mg/kg', 'Bougie', 'End-tidal CO₂ detector', 'Syringe for cuff (10 mL)'],
    steps: [
      { text: 'Assess airway: LEMON (Look, Evaluate 3-3-2, Mallampati, Obstruction, Neck mobility)', critical: true },
      { text: 'Pre-oxygenate: 100% O₂ × 3 min (or 8 vital capacity breaths)', critical: true },
      { text: 'Position: sniffing position (ear to sternal notch alignment)', critical: false },
      { text: 'Prepare backup plan: bougie, supraglottic airway (LMA), surgical cricothyrotomy kit', critical: true },
      { text: 'Push induction agent (Ketamine if hypotensive, Propofol if stable)', critical: false },
      { text: 'Push paralytic (Succinylcholine or Rocuronium)', critical: false },
      { text: 'Wait 45-60 seconds for full paralysis', critical: false },
      { text: 'Laryngoscopy: insert blade, lift epiglottis (Mac) →identify vocal cords', critical: false },
      { text: 'Pass ETT through cords — stop when cuff is 2 cm past cords', critical: true },
      { text: 'Inflate cuff, remove stylet', critical: false },
      { text: 'Confirm placement: EtCO₂ (GOLD STANDARD), bilateral breath sounds, no epigastric sounds, chest rise', critical: true },
      { text: 'Secure tube and note depth at teeth (21-23 cm for adult)', critical: false },
      { text: 'Obtain CXR for tube position (tip 2-4 cm above carina)', critical: false },
      { text: 'Start ventilator settings (TV 6-8 mL/kg IBW, RR 14-16, FiO₂ 100% → titrate)', critical: false },
    ],
    pearls: ['END-TIDAL CO₂ is the ONLY reliable confirmation', 'Rocuronium preferred if succinylcholine contraindicated (hyperkalemia, burns, denervation)', 'BURP maneuver (backward, upward, rightward pressure) improves view', 'If can\'t intubate, can\'t oxygenate → surgical airway (cricothyrotomy)'] },
  { id: 'paracentesis', title: 'Paracentesis', cat: 'Gastroenterology', difficulty: 'Intermediate', time: '15-20 min',
    equipment: ['Paracentesis kit or 18G needle + syringe', 'Sterile drapes, gloves', 'Chlorhexidine', 'Lidocaine 1%', 'Specimen tubes', 'Vacuum bottles (if therapeutic, 4-6L)', 'Albumin (if removing >5L: give 6-8g per L removed)'],
    steps: [
      { text: 'Confirm ascites clinically or with bedside US', critical: false },
      { text: 'Position: supine, slightly left lateral decubitus', critical: false },
      { text: 'Identify insertion point: LLQ (2 finger-breadths medial + cephalad to ASIS)', critical: true },
      { text: 'Verify no bowel/vessels at site with US', critical: true },
      { text: 'Sterile prep and drape', critical: true },
      { text: 'Anesthetize with lidocaine (skin through peritoneum)', critical: false },
      { text: 'Insert needle using Z-track technique (pull skin 2 cm caudally before puncturing)', critical: false },
      { text: 'Advance until fluid returns', critical: false },
      { text: 'Collect diagnostic samples: cell count, albumin, protein, cultures (inoculate blood culture bottles at bedside)', critical: true },
      { text: 'If therapeutic: connect to vacuum bottles and drain slowly', critical: false },
      { text: 'Remove needle, apply dressing', critical: false },
      { text: 'If >5L removed: give IV albumin 6-8g per liter removed', critical: true },
    ],
    pearls: ['SAAG ≥1.1 = portal hypertension. PMN ≥250 = spontaneous bacterial peritonitis (SBP)', 'No need to correct INR/platelets before paracentesis in cirrhosis', 'Z-track prevents post-procedure ascites leak', 'Always check cell count — even if fluid looks clear (SBP can be clear)'] },
];

function ProcedureChecklistView() {
  const [activeId, setActiveId] = useState(null);
  const [checked, setChecked] = useState({});
  const active = PROCEDURE_CHECKLISTS.find(p => p.id === activeId);

  const toggle = (idx) => {
    const key = `${activeId}_${idx}`;
    setChecked(p => ({ ...p, [key]: !p[key] }));
  };

  const progress = active ? active.steps.filter((_, i) => checked[`${activeId}_${i}`]).length : 0;
  const total = active ? active.steps.length : 0;

  return (
    <div className="flex-1 min-h-0 flex flex-col">
      <div className="px-4 py-3 shrink-0" style={{ borderBottom: '1px solid var(--border)' }}>
        <h2 className="font-black text-xl flex items-center gap-2">✅ Procedure Checklists</h2>
        <p className="text-xs opacity-40 mt-0.5">Step-by-step clinical procedures</p>
      </div>
      <div className="flex-1 min-h-0 overflow-y-auto custom-scrollbar p-4 space-y-3">
        {active ? (
          <div className="space-y-4 animate-fade-in-up">
            <div className="flex items-center gap-3">
              <button onClick={() => { setActiveId(null); }} className="glass w-9 h-9 rounded-xl flex items-center justify-center"><ChevronLeft size={16} /></button>
              <div className="flex-1">
                <h2 className="font-bold">{active.title}</h2>
                <p className="text-xs opacity-40">{active.cat} · {active.difficulty} · ~{active.time}</p>
              </div>
              <div className="text-right">
                <span className="text-sm font-semibold" style={{ color: progress === total ? '#10b981' : 'var(--accent)' }}>{progress}/{total}</span>
              </div>
            </div>

            {/* Progress bar */}
            <div className="h-2 rounded-full overflow-hidden" style={{ background: 'var(--border)' }}>
              <div className="h-full rounded-full transition-all" style={{ width: `${total > 0 ? (progress / total) * 100 : 0}%`, background: progress === total ? '#10b981' : 'var(--accent)' }} />
            </div>

            {/* Equipment */}
            <div className="glass rounded-2xl p-4" style={{ border: '1px solid var(--border)' }}>
              <h3 className="text-xs font-bold uppercase tracking-widest opacity-40 mb-3">🧰 Equipment</h3>
              <div className="grid grid-cols-1 sm:grid-cols-2 gap-1.5">
                {active.equipment.map((eq, i) => (
                  <div key={i} className="flex items-center gap-2 text-xs py-1">
                    <span style={{ color: 'var(--accent)' }}>▪</span>
                    <span className="opacity-70">{eq}</span>
                  </div>
                ))}
              </div>
            </div>

            {/* Steps */}
            <div className="space-y-2">
              {active.steps.map((s, i) => {
                const isDone = checked[`${activeId}_${i}`];
                return (
                  <button key={i} onClick={() => toggle(i)}
                    className="w-full flex items-start gap-3 glass rounded-2xl p-4 text-left transition-all"
                    style={{ border: `1px solid ${s.critical ? '#f59e0b30' : 'var(--border)'}`, opacity: isDone ? .5 : 1 }}>
                    <div className="w-6 h-6 rounded-lg flex items-center justify-center shrink-0 mt-0.5 transition-all"
                      style={isDone ? { background: '#10b981', color: '#fff' } : { background: 'var(--surface,var(--card))', border: '2px solid var(--border)' }}>
                      {isDone && <CheckCircle2 size={14} />}
                    </div>
                    <div className="flex-1">
                      <span className={`text-sm ${isDone ? 'line-through opacity-50' : 'font-bold'}`}>{s.text}</span>
                      {s.critical && !isDone && <span className="ml-2 text-xs px-1.5 py-0.5 rounded" style={{ background: '#f59e0b15', color: '#f59e0b' }}>CRITICAL</span>}
                    </div>
                    <span className="text-xs opacity-20 shrink-0 pt-1">{i + 1}</span>
                  </button>
                );
              })}
            </div>

            {/* Pearls */}
            {active.pearls?.length > 0 && (
              <div className="glass rounded-2xl p-5" style={{ border: '1px solid #f59e0b20', background: '#f59e0b05' }}>
                <h3 className="font-bold text-sm flex items-center gap-2 mb-3" style={{ color: '#f59e0b' }}>💎 Clinical Pearls</h3>
                {active.pearls.map((p, i) => <div key={i} className="flex gap-2 text-xs py-1"><span style={{ color: '#f59e0b' }}>▸</span><span className="opacity-70 leading-relaxed">{p}</span></div>)}
              </div>
            )}
          </div>
        ) : (
          PROCEDURE_CHECKLISTS.map(p => (
            <button key={p.id} onClick={() => setActiveId(p.id)}
              className="w-full glass rounded-2xl p-5 text-left transition-all card-hover"
              style={{ border: '1px solid var(--border)' }}>
              <div className="flex items-start justify-between gap-3 mb-2">
                <h3 className="font-bold">{p.title}</h3>
                <span className="px-2.5 py-1 rounded-lg text-xs font-bold shrink-0"
                  style={{ background: p.difficulty === 'Advanced' ? '#ef444415' : '#f59e0b15', color: p.difficulty === 'Advanced' ? '#ef4444' : '#f59e0b' }}>
                  {p.difficulty}
                </span>
              </div>
              <p className="text-xs opacity-50">{p.cat} · {p.steps.length} steps · ~{p.time}</p>
            </button>
          ))
        )}
      </div>
    </div>
  );
}

/* ═══════════════════════════════════════════════════════════════════
   EVIDENCE-BASED MEDICINE TOOLS — PICO, NNT, study appraisal
═══════════════════════════════════════════════════════════════════ */
function EBMToolsView({ settings, addToast }) {
  const [tab, setTab] = useState('nnt'); // nnt | pico | appraise
  const [nntForm, setNntForm] = useState({ cer: '', eer: '' });
  const [nntResult, setNntResult] = useState(null);
  const [picoForm, setPicoForm] = useState({ p: '', i: '', c: '', o: '' });
  const [picoResult, setPicoResult] = useState('');
  const [picoLoading, setPicoLoading] = useState(false);
  const [appraiseStudy, setAppraiseStudy] = useState('');
  const [appraiseResult, setAppraiseResult] = useState('');
  const [appraiseLoading, setAppraiseLoading] = useState(false);

  const calcNNT = () => {
    const cer = parseFloat(nntForm.cer) / 100;
    const eer = parseFloat(nntForm.eer) / 100;
    if (isNaN(cer) || isNaN(eer) || cer === eer) { setNntResult(null); return; }
    const arr = Math.abs(cer - eer);
    const nnt = Math.ceil(1 / arr);
    const rr = eer / cer;
    const rrr = Math.abs(1 - rr);
    setNntResult({
      arr: (arr * 100).toFixed(1) + '%',
      nnt,
      rr: rr.toFixed(2),
      rrr: (rrr * 100).toFixed(1) + '%',
      benefit: eer < cer,
    });
  };

  const generatePICO = async () => {
    if (!picoForm.p.trim()) { addToast('Fill in the Patient/Population field', 'warn'); return; }
    if (!settings.apiKey) { addToast('Set an API key in Settings', 'warn'); return; }
    setPicoLoading(true); setPicoResult('');
    try {
      await callAIStreaming(
        `Using the PICO framework, formulate a clinical question and suggest search strategy.
P (Patient/Population): ${picoForm.p}
I (Intervention): ${picoForm.i || 'Not specified'}
C (Comparison): ${picoForm.c || 'Standard of care'}
O (Outcome): ${picoForm.o || 'Not specified'}

Provide:
1. Well-formed clinical question
2. Search strategy (MeSH terms, Boolean operators)
3. Study type to look for (RCT, cohort, etc.)
4. Key databases to search
5. 2-3 example studies that might answer this question

Keep response concise (200 words).`,
        chunk => { setPicoResult(p => p + chunk); },
        settings, 400
      );
    } catch (e) { addToast('PICO generation failed', 'error'); }
    setPicoLoading(false);
  };

  const appraiseStudyFn = async () => {
    if (!appraiseStudy.trim()) return;
    if (!settings.apiKey) { addToast('Set an API key in Settings', 'warn'); return; }
    setAppraiseLoading(true); setAppraiseResult('');
    try {
      await callAIStreaming(
        `Critically appraise this clinical study abstract/description:

"${appraiseStudy}"

Evaluate using CASP (Critical Appraisal Skills Programme) criteria:
1. Study design validity
2. Risk of bias assessment
3. Sample size adequacy
4. Statistical significance vs clinical significance
5. Confounders and limitations
6. Generalizability (external validity)
7. Overall level of evidence (Oxford CEBM)
8. Bottom line: Is this evidence strong enough to change practice?

Keep response under 300 words. Be balanced — note strengths AND weaknesses.`,
        chunk => { setAppraiseResult(p => p + chunk); },
        settings, 500
      );
    } catch (e) { addToast('Appraisal failed', 'error'); }
    setAppraiseLoading(false);
  };

  return (
    <div className="flex-1 min-h-0 flex flex-col">
      <div className="px-4 py-3 shrink-0" style={{ borderBottom: '1px solid var(--border)' }}>
        <h2 className="font-black text-xl flex items-center gap-2">📊 EBM Tools</h2>
        <div className="flex gap-2 mt-3">
          {[['nnt', 'NNT Calculator'], ['pico', 'PICO Builder'], ['appraise', 'Study Appraisal']].map(([id, label]) => (
            <button key={id} onClick={() => setTab(id)}
              className="px-3 py-1.5 rounded-xl text-xs font-bold transition-all"
              style={tab === id ? { background: 'var(--accent)', color: '#fff' } : { opacity: .5 }}>
              {label}
            </button>
          ))}
        </div>
      </div>
      <div className="flex-1 min-h-0 overflow-y-auto custom-scrollbar p-4 space-y-4">
        {tab === 'nnt' && (
          <>
            <div className="glass rounded-2xl p-5 space-y-4" style={{ border: '1px solid var(--border)' }}>
              <h3 className="font-bold text-sm">Number Needed to Treat (NNT)</h3>
              <div className="grid grid-cols-2 gap-4">
                <div>
                  <label className="text-xs font-bold opacity-40 block mb-2">Control Event Rate (%)</label>
                  <input type="number" value={nntForm.cer} onChange={e => setNntForm(p => ({ ...p, cer: e.target.value }))}
                    placeholder="e.g. 20" className="w-full glass-input rounded-xl px-4 py-2.5 text-sm outline-none" style={{ border: '1px solid var(--border)' }} />
                  <p className="text-xs opacity-30 mt-1">Event rate in placebo/control group</p>
                </div>
                <div>
                  <label className="text-xs font-bold opacity-40 block mb-2">Experimental Event Rate (%)</label>
                  <input type="number" value={nntForm.eer} onChange={e => setNntForm(p => ({ ...p, eer: e.target.value }))}
                    placeholder="e.g. 15" className="w-full glass-input rounded-xl px-4 py-2.5 text-sm outline-none" style={{ border: '1px solid var(--border)' }} />
                  <p className="text-xs opacity-30 mt-1">Event rate in treatment group</p>
                </div>
              </div>
              <button onClick={calcNNT} className="btn-accent w-full py-3 rounded-xl font-bold">Calculate</button>
            </div>
            {nntResult && (
              <div className="glass rounded-2xl p-6 text-center animate-scale-in" style={{ border: '1px solid var(--accent)/30' }}>
                <div className="text-xl font-bold mb-2" style={{ color: 'var(--accent)' }}>NNT = {nntResult.nnt}</div>
                <p className="text-sm opacity-60 mb-4">
                  {nntResult.benefit
                    ? `Treat ${nntResult.nnt} patients to prevent 1 additional event`
                    : `${nntResult.nnt} patients treated per 1 additional harm (NNH)`}
                </p>
                <div className="grid grid-cols-3 gap-3">
                  <div className="glass rounded-xl p-3" style={{ border: '1px solid var(--border)' }}>
                    <div className="text-lg font-black" style={{ color: '#10b981' }}>{nntResult.arr}</div>
                    <div className="text-xs opacity-40">ARR</div>
                  </div>
                  <div className="glass rounded-xl p-3" style={{ border: '1px solid var(--border)' }}>
                    <div className="text-lg font-black" style={{ color: '#3b82f6' }}>{nntResult.rr}</div>
                    <div className="text-xs opacity-40">RR</div>
                  </div>
                  <div className="glass rounded-xl p-3" style={{ border: '1px solid var(--border)' }}>
                    <div className="text-lg font-black" style={{ color: '#8b5cf6' }}>{nntResult.rrr}</div>
                    <div className="text-xs opacity-40">RRR</div>
                  </div>
                </div>
              </div>
            )}
          </>
        )}

        {tab === 'pico' && (
          <>
            <div className="glass rounded-2xl p-5 space-y-3" style={{ border: '1px solid var(--border)' }}>
              <h3 className="font-bold text-sm">PICO Framework</h3>
              {[
                { key: 'p', label: 'P — Patient / Population', placeholder: 'e.g. Adult patients with type 2 diabetes' },
                { key: 'i', label: 'I — Intervention', placeholder: 'e.g. SGLT2 inhibitors' },
                { key: 'c', label: 'C — Comparison', placeholder: 'e.g. Metformin alone' },
                { key: 'o', label: 'O — Outcome', placeholder: 'e.g. HbA1c reduction, CV events' },
              ].map(f => (
                <div key={f.key}>
                  <label className="text-xs font-bold opacity-50 block mb-1">{f.label}</label>
                  <input value={picoForm[f.key]} onChange={e => setPicoForm(p => ({ ...p, [f.key]: e.target.value }))}
                    placeholder={f.placeholder}
                    className="w-full glass-input rounded-xl px-4 py-2.5 text-sm outline-none" style={{ border: '1px solid var(--border)' }} />
                </div>
              ))}
              <button onClick={generatePICO} disabled={picoLoading}
                className="btn-accent w-full py-3 rounded-xl font-bold flex items-center justify-center gap-2">
                {picoLoading ? <><Loader2 size={16} className="animate-spin" /> Generating…</> : <><Sparkles size={16} /> Build PICO Question</>}
              </button>
            </div>
            {picoResult && (
              <div className="glass rounded-2xl p-5 animate-fade-in-up" style={{ border: '1px solid var(--border)' }}>
                <p className="text-sm opacity-80 leading-relaxed whitespace-pre-wrap">{picoResult}</p>
              </div>
            )}
          </>
        )}

        {tab === 'appraise' && (
          <>
            <div className="glass rounded-2xl p-5 space-y-3" style={{ border: '1px solid var(--border)' }}>
              <h3 className="font-bold text-sm">Critical Appraisal</h3>
              <textarea value={appraiseStudy} onChange={e => setAppraiseStudy(e.target.value)}
                rows={6} placeholder="Paste a study abstract or describe the study design, methods, results, and conclusions…"
                className="w-full glass-input rounded-xl px-4 py-3 text-sm outline-none resize-none" style={{ border: '1px solid var(--border)' }} />
              <button onClick={appraiseStudyFn} disabled={appraiseLoading || !appraiseStudy.trim()}
                className="btn-accent w-full py-3 rounded-xl font-bold flex items-center justify-center gap-2">
                {appraiseLoading ? <><Loader2 size={16} className="animate-spin" /> Appraising…</> : <><Sparkles size={16} /> Appraise Study</>}
              </button>
            </div>
            {appraiseResult && (
              <div className="glass rounded-2xl p-5 animate-fade-in-up" style={{ border: '1px solid var(--border)' }}>
                <p className="text-sm opacity-80 leading-relaxed whitespace-pre-wrap">{appraiseResult}</p>
              </div>
            )}
          </>
        )}
      </div>
    </div>
  );
}

