/* ═══════════════════════════════════════════════════════════════════
   COMMUNICATION SKILLS — Breaking bad news, MI, etc.
═══════════════════════════════════════════════════════════════════ */
const COMM_FRAMEWORKS = [
  { id: 'spikes', title: 'SPIKES — Breaking Bad News', icon: '💬',
    steps: [
      { letter: 'S', name: 'Setting', items: ['Arrange privacy (close curtain, quiet room)', 'Sit at eye level', 'Involve significant others (per patient preference)', 'Make connection (eye contact, touch if appropriate)', 'Manage time: uninterrupted block', 'Turn off phone / pager if possible'] },
      { letter: 'P', name: 'Perception', items: ['Ask before telling: "What have you been told about your condition?"', '"What is your understanding of why we did the test?"', 'Assess level of understanding and expectations', 'Correct misinformation gently', 'Identify denial as a coping mechanism'] },
      { letter: 'I', name: 'Invitation', items: ['"Would you like me to give you the full information about the results?"', 'Some patients prefer not to know details — respect autonomy', '"How much detail would you like me to go into?"', 'Identify who else should hear the information'] },
      { letter: 'K', name: 'Knowledge', items: ['Warning shot: "I\'m sorry, I have some difficult news…"', 'Use simple language (avoid jargon)', 'Give information in small chunks', 'Check understanding after each piece', 'Avoid phrases like "there\'s nothing we can do" (always something: palliation, support)'] },
      { letter: 'E', name: 'Emotions / Empathy', items: ['Allow silence — do not rush to fill it', 'Acknowledge emotion: "I can see this is upsetting…"', 'Validate: "It\'s completely understandable to feel angry"', 'Use NURSE statements: Name, Understand, Respect, Support, Explore', 'Offer tissues, water. Be present.'] },
      { letter: 'S', name: 'Strategy / Summary', items: ['Discuss next steps and treatment options', 'Check understanding: "Can you tell me what you\'ve taken from today?"', 'Arrange follow-up (specific date/time)', 'Provide written information / resources', 'Offer referrals: social work, pastoral care, support groups', '"I will be here for you throughout this process"'] },
    ]},
  { id: 'mi', title: 'Motivational Interviewing', icon: '🎯',
    steps: [
      { letter: 'O', name: 'Open-ended Questions', items: ['"Tell me about your experience with…"', '"What concerns you most about…?"', '"How would you like things to be different?"', 'Avoids yes/no answers', 'Gives patient control of the narrative'] },
      { letter: 'A', name: 'Affirmations', items: ['Acknowledge strengths and efforts', '"It takes courage to come in today"', '"You\'ve clearly been thinking about this carefully"', 'Reinforce positive behavior change talk', 'Build self-efficacy'] },
      { letter: 'R', name: 'Reflections', items: ['Simple reflection: repeat/rephrase what patient said', 'Complex reflection: add meaning or emotional content', '"It sounds like you\'re torn between wanting to quit and enjoying smoking"', 'Amplified reflection (for resistance): slightly exaggerate → patient corrects', 'Reflect the change talk, not the sustain talk'] },
      { letter: 'S', name: 'Summaries', items: ['Collecting summary: gather change talk statements together', '"So on one hand you enjoy drinking socially, but on the other hand you\'re worried about your liver"', 'Linking summary: connect current to previous sessions', 'Transitional summary: shift to planning phase', 'Always end with: "What did I miss?"'] },
    ],
    extras: [
      'Spirit of MI: Partnership (collaborate), Acceptance (autonomy, empathy), Compassion, Evocation (draw out their motivation)',
      'Change Talk (DARN-CAT): Desire, Ability, Reason, Need, Commitment, Activation, Taking steps',
      'Roll with resistance — do NOT argue or confront directly',
      'Develop discrepancy: help patient see gap between current behavior and stated goals/values',
      'Readiness ruler: "On a scale of 1-10, how ready are you to…?" → "Why not a lower number?"',
    ]},
  { id: 'consent', title: 'Informed Consent', icon: '📋',
    steps: [
      { letter: 'D', name: 'Diagnosis / Condition', items: ['Explain the current condition clearly', 'Use layperson terms', 'Check understanding'] },
      { letter: 'P', name: 'Procedure / Treatment', items: ['Describe what will be done, step by step', 'Explain who will perform it', 'Duration and recovery expectations'] },
      { letter: 'R', name: 'Risks', items: ['Common risks (even if minor)', 'Serious risks (even if rare)', 'Specific risks relevant to THIS patient', 'Use numbers when possible: "About 1 in 100 patients…"'] },
      { letter: 'B', name: 'Benefits', items: ['Expected benefits of the procedure', 'Likelihood of success', 'What happens if successful'] },
      { letter: 'A', name: 'Alternatives', items: ['Other treatment options', 'Including no treatment (watchful waiting)', 'Risks/benefits of alternatives'] },
      { letter: 'Q', name: 'Questions', items: ['Invite questions: "What questions do you have?"', 'NOT "Do you have any questions?" (less effective)', 'Confirm understanding: teach-back method', 'Document consent discussion'] },
    ],
    extras: [
      'Capacity assessment: patient must understand, appreciate, reason, and communicate a choice',
      'Competence is a legal determination (by court). Capacity is clinical (by any physician).',
      'Emergency exception: implied consent if immediate threat to life and patient unable to consent',
      'Minors: generally need parental consent. Exceptions: emancipated minor, emergency, STI/contraception/substance abuse (state-dependent)',
    ]},
];

